public Player addPlayer(Player current, Player newPlayer)
{
    if (current == null)
    {
        return newPlayer;
    }

    if (newPlayer.getScore() < current.getScore())
    {
        // Recurse down the left subtree
        current.left = addPlayer(current.left, newPlayer);
    }
    else
    {
        // Recurse down the right subtree
        current.right = addPlayer(current.right, newPlayer);
    }

    return current;
}
```

